# Tool Name: cwe_113_0_v1_tool
# Description: Helper function to store specific pieces of information in an HTTP response header.
# Arguments: header (dict), info_type (str), content (str)
# Returns: Updated header dictionary with new information or unchanged if the info type is not recognized.
# Requires: None
def cwe_113_0_v1_tool(header, info_type, content):
    """Store specific pieces of information in an HTTP response header."""
    if info_type == 'lang':
        header['Accept-Language'] = content
    elif info_type == 'encoding':
        header['Content-Encoding'] = content
    elif info_type == 'cache':
        header['Cache-Control'] = content
    else:
        return "Information type not recognized. Header remains unchanged."

    return header

# Example usage:
header = {'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8'}
info_type = 'lang'
content = 'en-US'
result = cwe_113_0_v1_tool(header, info_type, content)
print(result)  # {'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8', 'Accept-Language': 'en-US'}

